import React, { useEffect, useState } from "react";
import * as api from "../utils/api";
import "./AppointmentForm.css";

const initialForm = {
  patientName: "",
  doctorId: "",
  appointmentDate: "",
  appointmentTime: "",
  reason: "",
};

const fallbackDoctors = [
  { id: "d1", name: "Dr. A (Cardiology)", specialization: "Cardiology" },
  { id: "d2", name: "Dr. B (Neurology)", specialization: "Neurology" },
  { id: "d3", name: "Dr. C (Orthopedics)", specialization: "Orthopedics" },
  { id: "d4", name: "Dr. D (Dermatology)", specialization: "Dermatology" },
  { id: "d5", name: "Dr. E (Pediatrics)", specialization: "Pediatrics" },
  { id: "d6", name: "Dr. F (Psychiatry)", specialization: "Psychiatry" },
];

export default function AppointmentForm({ onBooked } = {}) {
  const [form, setForm] = useState(initialForm);
  const [errors, setErrors] = useState({});
  const [successMessage, setSuccessMessage] = useState("");
  const [serverError, setServerError] = useState("");
  const [doctors, setDoctors] = useState([]);
  const [loading, setLoading] = useState(false);
  const [submitting, setSubmitting] = useState(false);

  useEffect(() => {
    let mounted = true;
    setLoading(true);
    api
      .fetchDoctors()
      .then((d) => {
        if (!mounted) return;
        // Ensure at least 6 doctors with different specialties by merging fallback list
        const uniq = [];
        const seenSpecs = new Set();
        (d || [])
          .concat(fallbackDoctors)
          .forEach((doc) => {
            const spec = (doc.specialization || "").toLowerCase();
            if (!seenSpecs.has(spec)) {
              seenSpecs.add(spec);
              uniq.push(doc);
            }
          });
        // slice to keep deterministic size (at least 6 if available)
        setDoctors(uniq.slice(0, Math.max(6, uniq.length)));
      })
      .catch(() => {
        if (!mounted) return;
        setDoctors(fallbackDoctors);
      })
      .finally(() => mounted && setLoading(false));
    return () => (mounted = false);
  }, []);

  const handleChange = (field) => (e) => {
    setForm((s) => ({ ...s, [field]: e.target.value }));
    setErrors((prev) => ({ ...prev, [field]: "" }));
    setSuccessMessage("");
    setServerError("");
  };

  const validate = () => {
    const e = {};
    if (!form.patientName || form.patientName.trim().length < 1)
      e.patientName = "Patient name is required";
    if (!form.doctorId) e.doctorId = "Doctor is required";
    if (!form.appointmentDate) e.appointmentDate = "Appointment date is required";
    if (!form.appointmentTime) e.appointmentTime = "Appointment time is required";
    if (!form.reason) e.reason = "Reason is required";
    else if (form.reason.trim().length < 10) e.reason = "Reason must be at least 10 characters";
    else if (form.reason.trim().length > 200) e.reason = "Reason must be at most 200 characters";
    setErrors(e);
    return Object.keys(e).length === 0;
  };

  const findPatientByName = async (name) => {
    // Best-effort: try to find an existing patient by fetching list, fallback to creating one.
    try {
      const patients = await api.fetchPatients();
      const found = (patients || []).find(
        (p) => p.name && p.name.toLowerCase() === name.toLowerCase()
      );
      if (found) return found.id;
    } catch {
      // ignore and create
    }
    // create minimal patient record (server must accept at least {name})
    const created = await api.createPatient({ name });
    return created.id;
  };

  const handleSubmit = async () => {
    setSuccessMessage("");
    setServerError("");
    if (!validate()) return;

    try {
      setSubmitting(true);
      // Resolve patientId (create if necessary)
      const patientId = await findPatientByName(form.patientName.trim());

      const payload = {
        patientId: Number(patientId),
        doctorId: Number(form.doctorId) || form.doctorId,
        appointmentDate: form.appointmentDate,
        appointmentTime: form.appointmentTime,
        reason: form.reason.trim(),
      };

      await api.createAppointment(payload);
      setForm(initialForm);
      setErrors({});
      setSuccessMessage("Appointment successfully booked");
      if (typeof onBooked === "function") onBooked();
    } catch (err) {
      setServerError(err?.message || "Server error");
    } finally {
      setSubmitting(false);
    }
  };

  return (
    <div className="appointment-card" aria-live="polite">
      <h2 className="appointment-title">Book Appointment</h2>

      {loading ? (
        <div>Loading doctors…</div>
      ) : (
        <form className="appointment-form" onSubmit={(e) => e.preventDefault()}>
          <div className="form-group">
            <label htmlFor="patient-name" className="field-label">Patient name</label>
            <input
              id="patient-name"
              data-testid="patient-name"
              className="field-input"
              value={form.patientName}
              onChange={handleChange("patientName")}
              placeholder="Enter your name"
            />
            {errors.patientName && <div className="field-error">{errors.patientName}</div>}
          </div>

          <div className="form-group">
            <label htmlFor="doctor-select" className="field-label">Doctor</label>
            <select
              id="doctor-select"
              data-testid="doctor-select"
              className="field-input"
              value={form.doctorId}
              onChange={handleChange("doctorId")}
            >
              <option value="">Select doctor</option>
              {doctors.map((d) => (
                <option key={d.id} value={d.id}>
                  {d.name} {d.specialization ? `(${d.specialization})` : ""}
                </option>
              ))}
            </select>
            {errors.doctorId && <div className="field-error">{errors.doctorId}</div>}
          </div>

          <div className="form-group">
            <label htmlFor="date-input" className="field-label">Appointment date</label>
            <input
              id="date-input"
              type="date"
              data-testid="date-input"
              className="field-input"
              value={form.appointmentDate}
              onChange={handleChange("appointmentDate")}
            />
            {errors.appointmentDate && <div className="field-error">{errors.appointmentDate}</div>}
          </div>

          <div className="form-group">
            <label htmlFor="time-input" className="field-label">Appointment time</label>
            <input
              id="time-input"
              type="time"
              data-testid="time-input"
              className="field-input"
              value={form.appointmentTime}
              onChange={handleChange("appointmentTime")}
            />
            {errors.appointmentTime && <div className="field-error">{errors.appointmentTime}</div>}
          </div>

          <div className="form-group">
            <label htmlFor="reason-input" className="field-label">Reason for appointment</label>
            <textarea
              id="reason-input"
              data-testid="reason-input"
              className="field-input textarea-field"
              value={form.reason}
              onChange={handleChange("reason")}
            />
            {errors.reason && <div className="field-error">{errors.reason}</div>}
          </div>

          {serverError && <div className="field-error" role="alert">{serverError}</div>}
          {successMessage && <div className="field-success">{successMessage}</div>}

          <button
            type="button"
            className="primary-btn"
            onClick={handleSubmit}
            disabled={submitting}
          >
            {submitting ? "Booking…" : "Book Appointment"}
          </button>
        </form>
      )}
    </div>
  );
}
